// Log the open event
const query = $input.first().json.query || {};
const event = {
  type: 'open',
  uid: query.uid || 'unknown',
  campaignId: query.cid || 'unknown',
  timestamp: new Date().toISOString(),
  ip: $input.first().json.headers?.['x-forwarded-for'] || 'unknown',
  userAgent: $input.first().json.headers?.['user-agent'] || 'unknown'
};

// Store in workflow static data
const staticData = $getWorkflowStaticData('global');
if (!staticData.events) staticData.events = [];
staticData.events.push(event);
// Keep last 10000 events
if (staticData.events.length > 10000) staticData.events = staticData.events.slice(-10000);

// Return a 1x1 transparent pixel
return [{ json: { headers: { 'Content-Type': 'image/gif' }, body: 'R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7' } }];

