input:focus{border-color:#1a73e8;outline:none;box-shadow:0 0 0 2px rgba(26,115,232,0.2)}
button{background:#1a73e8;color:white;border:none;padding:12px 24px;font-size:15px;border-radius:4px;cursor:pointer;font-weight:500;width:auto;float:right}
button:hover{background:#1557b0}.forgot{color:#1a73e8;font-size:14px;text-decoration:none;float:left;margin-top:8px}</style></head>
<body><div class="box">
