</form></div></body></html>`;

return [{ json: { headers: { 'Content-Type': 'text/html' }, body: html } }];

// Log click and redirect to training page (no credential capture)
const query = $input.first().json.query || {};
const event = {
  type: 'click',
  uid: query.uid || 'unknown',
  campaignId: query.cid || 'unknown',
  timestamp: new Date().toISOString()
};

const staticData = $getWorkflowStaticData('global');
if (!staticData.events) staticData.events = [];
staticData.events.push(event);

const trainingUrl = `https://palisadeone.com/phish-training.html?uid=${query.uid || ''}&cid=${query.cid || ''}`;

return [{ json: { headers: { 'Location': trainingUrl, 'Content-Type': 'text/html' }, statusCode: 302, body: `<html><body>Redirecting... <a href="${trainingUrl}">Click here</a></body></html>` } }];

// Log credential submission and redirect to training page
const query = $input.first().json.query || {};
const body = $input.first().json.body || {};

const event = {
  type: 'submit',
  uid: query.uid || 'unknown',
  campaignId: query.cid || 'unknown',
  timestamp: new Date().toISOString(),
  // We log THAT they submitted, but NOT the actual credentials (ethical best practice)
  emailEntered: body.email ? 'yes' : 'no',
  passwordEntered: body.password ? 'yes' : 'no'
};

const staticData = $getWorkflowStaticData('global');
if (!staticData.events) staticData.events = [];
staticData.events.push(event);

const trainingUrl = `https://palisadeone.com/phish-training.html?uid=${query.uid || ''}&cid=${query.cid || ''}`;

return [{ json: { headers: { 'Location': trainingUrl, 'Content-Type': 'text/html' }, statusCode: 302, body: `<html><body>Redirecting to training... <a href="${trainingUrl}">Click here</a></body></html>` } }];

// Return all tracked events for the dashboard to consume
const staticData = $getWorkflowStaticData('global');
const events = staticData.events || [];

// Return events and clear them (dashboard will merge into its local state)
staticData.events = [];

return [{ json: events }];
